// Withdrawal command builder. Everything is allowlisted: trees must be one of
// the five backed-up trees, dest must be a plain absolute path with no
// shell metacharacters — the webhook body never reaches a shell unvalidated.
const body = $json.body || {};
const action = String(body.action || 'list').toLowerCase();
const RCLONE = '/opt/homebrew/bin/rclone';
const REMOTE = 'dropbox:market-data-archive';
const TREES = ['market_cache', 'bhavcopy_cache', 'cache_seed', 'gmd_cache_seed', 'warehouse_duckdb'];

if (action === 'list') {
  return [{ json: { action, cmd: `${RCLONE} lsd ${REMOTE}/current --timeout 60s && ${RCLONE} size ${REMOTE}/current --json --timeout 60s` } }];
}
if (action === 'history') {
  // dated version folders — where changed/deleted files were moved, never destroyed
  return [{ json: { action, cmd: `${RCLONE} lsd ${REMOTE}/history --timeout 60s` } }];
}
if (action === 'restore') {
  const tree = body.tree;
  if (!TREES.includes(tree)) {
    throw new Error(`tree must be one of: ${TREES.join(', ')}`);
  }
  const dest = body.dest || `/Users/umashankar/restore/${tree}`;
  if (!/^\/[A-Za-z0-9_\/.\-]+$/.test(dest) || dest.includes('..')) {
    throw new Error('dest must be a plain absolute path (A-Za-z0-9_/.- only, no ..)');
  }
  const src = body.date
    ? `${REMOTE}/history/${body.date}/${tree}`   // pull a dated prior version
    : `${REMOTE}/current/${tree}`;
  if (body.date && !/^\d{4}-\d{2}-\d{2}$/.test(body.date)) {
    throw new Error('date must be YYYY-MM-DD');
  }
  return [{ json: { action, tree, dest, cmd: `mkdir -p '${dest}' && ${RCLONE} copy '${src}' '${dest}' --transfers 4 --retries 5 --low-level-retries 20 --stats-one-line --timeout 10m` } }];
}
throw new Error('action must be list | history | restore');
